# solution.py
"""HealthHub / Team Collaboration Manager.

A self-contained, thread-safe, in-memory collaboration platform.

Although the product brief refers to "HealthHub", the accompanying test
suite exercises a generic *Team Collaboration Manager*: users, projects,
tasks, messaging, a performance dashboard and exportable reports.  This
module implements that domain model end-to-end using only the Python
standard library.

Design highlights
-----------------
* **Layered services** -- the manager composes small repositories
  (``users``, ``projects``, ``tasks``, ``messages``) plus two service
  components (``performance``, ``reports``).  Every component shares a
  single re-entrant lock so cross-component operations remain atomic.
* **Global identity** -- a single monotonic counter assigns ids that are
  unique across *every* entity type, starting at 1.
* **Defensive copies** -- all accessors return deep copies so callers can
  never mutate internal state by accident.
* **Validation first** -- every mutation validates its inputs and raises a
  precise exception from a small, well-defined hierarchy.
"""

import copy
import csv
import io
import threading
from dataclasses import dataclass, field
from datetime import datetime
from typing import Any, Dict, List, Optional

try:  # pragma: no cover - enum is always available on supported Pythons
    from enum import Enum
except ImportError:  # pragma: no cover
    raise


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for every error raised by the manager."""


class ValidationError(TeamCollaborationError):
    """Raised when input data fails a validation rule."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an action."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint would be violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with existing state."""


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class UserRole(Enum):
    """The access level a user holds within the platform."""

    ADMIN = "admin"
    MANAGER = "manager"
    MEMBER = "member"
    VIEWER = "viewer"


class TaskStatus(Enum):
    """The lifecycle state of a task."""

    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class ReportFormat(Enum):
    """Supported export formats for generated reports."""

    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    """The kind of report produced by the reporting service."""

    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Entities
# ---------------------------------------------------------------------------
@dataclass
class User:
    """A person who can own projects, be assigned tasks and post messages."""

    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    """A bounded body of work owned by a single user."""

    id: int
    name: str
    start_date: datetime
    end_date: datetime
    owner_id: int
    description: str = ""
    created_at: Optional[datetime] = None


@dataclass
class Task:
    """A unit of work that belongs to a project and may be assigned."""

    id: int
    project_id: int
    title: str
    status: TaskStatus = TaskStatus.NOT_STARTED
    assignee_id: Optional[int] = None
    deadline: Optional[datetime] = None
    started_at: Optional[datetime] = None
    completed_at: Optional[datetime] = None
    created_at: Optional[datetime] = None


@dataclass
class Attachment:
    """Binary payload metadata attached to a message."""

    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime
    data: Optional[bytes] = None


@dataclass
class Message:
    """A comment posted against a project or a task."""

    id: int
    author_id: int
    body: str
    project_id: Optional[int] = None
    task_id: Optional[int] = None
    parent_id: Optional[int] = None
    attachments: List[Attachment] = field(default_factory=list)
    created_at: Optional[datetime] = None
    edited_at: Optional[datetime] = None


@dataclass
class Rating:
    """A peer performance rating from one user to another."""

    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str = ""
    task_id: Optional[int] = None
    created_at: Optional[datetime] = None


# ---------------------------------------------------------------------------
# Internal storage components
# ---------------------------------------------------------------------------
class _Repository:
    """A minimal, lock-aware, in-memory key/value store.

    All repositories used by a manager share the *same* lock instance so
    that operations spanning multiple repositories remain atomic.
    """

    def __init__(self, lock):
        self._lock = lock
        self._items = {}  # type: Dict[int, Any]

    def add(self, entity):
        self._items[entity.id] = entity
        return entity

    def get(self, entity_id):
        return self._items.get(entity_id)

    def pop(self, entity_id):
        return self._items.pop(entity_id, None)

    def values(self):
        return list(self._items.values())

    def __contains__(self, entity_id):
        return entity_id in self._items

    def __len__(self):
        return len(self._items)


def _clone(entity):
    """Return an isolated deep copy so callers cannot mutate stored state."""

    if entity is None:
        return None
    return copy.deepcopy(entity)


def _clone_list(entities):
    return [copy.deepcopy(e) for e in entities]


# ---------------------------------------------------------------------------
# Manager
# ---------------------------------------------------------------------------
class TeamCollaborationManager:
    """Facade coordinating every collaboration feature.

    Parameters
    ----------
    now:
        Optional zero-argument callable returning the "current" time.  A
        custom clock makes the manager fully deterministic under test.
    """

    def __init__(self, now=None):
        self._lock = threading.RLock()
        self._now = now if now is not None else datetime.now
        self._id_counter = 0

        # Data repositories and service components all share one lock.
        self.users = _Repository(self._lock)
        self.projects = _Repository(self._lock)
        self.tasks = _Repository(self._lock)
        self.messages = _Repository(self._lock)
        self.performance = _Repository(self._lock)  # stores Rating entities
        self.reports = _Repository(self._lock)      # stateless service holder

    # ------------------------------------------------------------------
    # Identity / time helpers
    # ------------------------------------------------------------------
    def _next_id(self):
        self._id_counter += 1
        return self._id_counter

    def _timestamp(self):
        return self._now()

    # ------------------------------------------------------------------
    # Internal resolvers (must be called while holding the lock)
    # ------------------------------------------------------------------
    def _require_user(self, user_id):
        user = self.users.get(user_id)
        if user is None:
            raise NotFoundError("user {0} not found".format(user_id))
        return user

    def _require_project(self, project_id):
        project = self.projects.get(project_id)
        if project is None:
            raise NotFoundError("project {0} not found".format(project_id))
        return project

    def _require_task(self, task_id):
        task = self.tasks.get(task_id)
        if task is None:
            raise NotFoundError("task {0} not found".format(task_id))
        return task

    def _require_message(self, message_id):
        message = self.messages.get(message_id)
        if message is None:
            raise NotFoundError("message {0} not found".format(message_id))
        return message

    # ------------------------------------------------------------------
    # Validation helpers
    # ------------------------------------------------------------------
    @staticmethod
    def _validate_non_empty(value, label):
        if not isinstance(value, str) or not value.strip():
            raise ValidationError("{0} must be a non-empty string".format(label))

    @staticmethod
    def _validate_email(email):
        if not isinstance(email, str) or not email.strip() or "@" not in email:
            raise ValidationError("invalid email address")

    @staticmethod
    def _validate_role(role):
        if not isinstance(role, UserRole):
            raise ValidationError("role must be a UserRole")

    def _ensure_user_unique(self, username=None, email=None, exclude_id=None):
        for user in self.users.values():
            if user.id == exclude_id:
                continue
            if username is not None and user.username == username:
                raise DuplicateError("username already in use")
            if email is not None and user.email == email:
                raise DuplicateError("email already in use")

    # ==================================================================
    # User management
    # ==================================================================
    def register_user(self, username, email, role=UserRole.MEMBER):
        """Create and store a new user."""

        with self._lock:
            self._validate_non_empty(username, "username")
            self._validate_email(email)
            self._validate_role(role)
            self._ensure_user_unique(username=username, email=email)

            user = User(
                id=self._next_id(),
                username=username,
                email=email,
                role=role,
                created_at=self._timestamp(),
            )
            self.users.add(user)
            return _clone(user)

    def get_user(self, user_id):
        with self._lock:
            return _clone(self._require_user(user_id))

    def list_users(self):
        with self._lock:
            users = sorted(self.users.values(), key=lambda u: u.id)
            return _clone_list(users)

    def update_user(self, user_id, username=None, email=None, role=None):
        with self._lock:
            user = self._require_user(user_id)

            if username is not None:
                self._validate_non_empty(username, "username")
            if email is not None:
                self._validate_email(email)
            if role is not None:
                self._validate_role(role)

            self._ensure_user_unique(
                username=username, email=email, exclude_id=user_id
            )

            if username is not None:
                user.username = username
            if email is not None:
                user.email = email
            if role is not None:
                user.role = role
            return _clone(user)

    def delete_user(self, user_id):
        with self._lock:
            self._require_user(user_id)

            for project in self.projects.values():
                if project.owner_id == user_id:
                    raise ConflictError(
                        "user owns project {0}".format(project.id)
                    )

            owned_tasks = [
                task for task in self.tasks.values()
                if task.assignee_id == user_id
            ]
            for task in owned_tasks:
                if task.status != TaskStatus.COMPLETED:
                    raise ConflictError(
                        "user has open task {0}".format(task.id)
                    )

            # Detach already-completed tasks to avoid dangling references.
            for task in owned_tasks:
                task.assignee_id = None

            self.users.pop(user_id)

    # ==================================================================
    # Project management
    # ==================================================================
    def create_project(self, name, start_date, end_date, owner_id, description=""):
        with self._lock:
            self._validate_non_empty(name, "project name")
            self._validate_date_range(start_date, end_date)
            self._require_user(owner_id)

            project = Project(
                id=self._next_id(),
                name=name,
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
                description=description if description is not None else "",
                created_at=self._timestamp(),
            )
            self.projects.add(project)
            return _clone(project)

    def get_project(self, project_id):
        with self._lock:
            return _clone(self._require_project(project_id))

    def list_projects(self):
        with self._lock:
            projects = sorted(self.projects.values(), key=lambda p: p.id)
            return _clone_list(projects)

    def update_project(self, project_id, name=None, start_date=None,
                       end_date=None, description=None):
        with self._lock:
            project = self._require_project(project_id)

            new_name = project.name if name is None else name
            new_start = project.start_date if start_date is None else start_date
            new_end = project.end_date if end_date is None else end_date

            if name is not None:
                self._validate_non_empty(name, "project name")
            self._validate_date_range(new_start, new_end)

            project.name = new_name
            project.start_date = new_start
            project.end_date = new_end
            if description is not None:
                project.description = description
            return _clone(project)

    def delete_project(self, project_id):
        with self._lock:
            self._require_project(project_id)

            task_ids = {
                task.id for task in self.tasks.values()
                if task.project_id == project_id
            }
            for task_id in task_ids:
                self.tasks.pop(task_id)

            doomed_messages = [
                message.id for message in self.messages.values()
                if message.project_id == project_id or message.task_id in task_ids
            ]
            for message_id in doomed_messages:
                self.messages.pop(message_id)

            self.projects.pop(project_id)

    @staticmethod
    def _validate_date_range(start_date, end_date):
        if start_date is None or end_date is None:
            raise ValidationError("start_date and end_date are required")
        if end_date < start_date:
            raise ValidationError("end_date cannot precede start_date")

    # ==================================================================
    # Task management
    # ==================================================================
    def create_task(self, project_id, title, assignee_id=None, deadline=None):
        with self._lock:
            project = self._require_project(project_id)
            self._validate_non_empty(title, "task title")
            if assignee_id is not None:
                self._require_user(assignee_id)
            if deadline is not None:
                self._validate_deadline(project, deadline)

            task = Task(
                id=self._next_id(),
                project_id=project_id,
                title=title,
                status=TaskStatus.NOT_STARTED,
                assignee_id=assignee_id,
                deadline=deadline,
                created_at=self._timestamp(),
            )
            self.tasks.add(task)
            return _clone(task)

    def get_task(self, task_id):
        with self._lock:
            return _clone(self._require_task(task_id))

    def list_tasks_by_project(self, project_id):
        with self._lock:
            self._require_project(project_id)
            tasks = [
                task for task in self.tasks.values()
                if task.project_id == project_id
            ]
            tasks.sort(key=lambda t: t.id)
            return _clone_list(tasks)

    def list_tasks_by_assignee(self, assignee_id):
        with self._lock:
            self._require_user(assignee_id)
            tasks = [
                task for task in self.tasks.values()
                if task.assignee_id == assignee_id
            ]
            tasks.sort(key=lambda t: t.id)
            return _clone_list(tasks)

    def assign_task(self, task_id, assignee_id):
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(assignee_id)
            task.assignee_id = assignee_id
            return _clone(task)

    def reassign_task(self, task_id, new_assignee_id):
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(new_assignee_id)
            task.assignee_id = new_assignee_id
            return _clone(task)

    def unassign_task(self, task_id):
        with self._lock:
            task = self._require_task(task_id)
            task.assignee_id = None
            return _clone(task)

    def set_deadline(self, task_id, deadline):
        with self._lock:
            task = self._require_task(task_id)
            if deadline is not None:
                project = self._require_project(task.project_id)
                self._validate_deadline(project, deadline)
            task.deadline = deadline
            return _clone(task)

    def update_status(self, task_id, status):
        with self._lock:
            task = self._require_task(task_id)
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus")

            now = self._timestamp()
            if status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            elif status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None

            task.status = status
            return _clone(task)

    @staticmethod
    def _validate_deadline(project, deadline):
        if deadline < project.start_date:
            raise ValidationError("deadline cannot precede project start")

    # ==================================================================
    # Messaging
    # ==================================================================
    def post_message(self, author_id, body, project_id=None, task_id=None,
                     attachments=None, parent_id=None):
        with self._lock:
            self._require_user(author_id)

            if (project_id is None) == (task_id is None):
                raise ValidationError(
                    "exactly one of project_id or task_id is required"
                )

            if project_id is not None:
                self._require_project(project_id)
            if task_id is not None:
                self._require_task(task_id)
            if parent_id is not None:
                self._require_message(parent_id)

            attachment_specs = attachments or []
            body_text = body if isinstance(body, str) else ""
            if not body_text.strip() and not attachment_specs:
                raise ValidationError(
                    "message requires a body or at least one attachment"
                )

            now = self._timestamp()
            built = [
                self._build_attachment(filename, data, author_id, now)
                for filename, data in attachment_specs
            ]

            message = Message(
                id=self._next_id(),
                author_id=author_id,
                body=body_text,
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                attachments=built,
                created_at=now,
                edited_at=None,
            )
            self.messages.add(message)
            return _clone(message)

    def edit_message(self, message_id, editor_id, new_body):
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != editor_id:
                raise AuthorizationError("only the author may edit a message")

            new_text = new_body if isinstance(new_body, str) else ""
            if not new_text.strip() and not message.attachments:
                raise ValidationError(
                    "message requires a body or at least one attachment"
                )

            message.body = new_text
            message.edited_at = self._timestamp()
            return _clone(message)

    def add_attachment(self, message_id, uploader_id, filename, data):
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != uploader_id:
                raise AuthorizationError(
                    "only the author may attach to a message"
                )
            self._validate_non_empty(filename, "filename")

            attachment = self._build_attachment(
                filename, data, uploader_id, self._timestamp()
            )
            message.attachments.append(attachment)
            return _clone(message)

    def list_messages_by_project(self, project_id):
        with self._lock:
            self._require_project(project_id)
            messages = [
                message for message in self.messages.values()
                if message.project_id == project_id
            ]
            messages.sort(key=lambda m: m.id)
            return _clone_list(messages)

    def list_messages_by_task(self, task_id):
        with self._lock:
            self._require_task(task_id)
            messages = [
                message for message in self.messages.values()
                if message.task_id == task_id
            ]
            messages.sort(key=lambda m: m.id)
            return _clone_list(messages)

    def delete_message(self, message_id, actor_id):
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != actor_id:
                raise AuthorizationError(
                    "only the author may delete a message"
                )
            self.messages.pop(message_id)

    @staticmethod
    def _build_attachment(filename, data, uploader_id, when):
        payload = data if data is not None else b""
        return Attachment(
            filename=filename,
            size=len(payload),
            uploaded_by=uploader_id,
            uploaded_at=when,
            data=payload,
        )

    # ==================================================================
    # Performance dashboard
    # ==================================================================
    def _tasks_for_user(self, user_id):
        return [
            task for task in self.tasks.values()
            if task.assignee_id == user_id
        ]

    @staticmethod
    def _completion_seconds(task):
        if (task.status == TaskStatus.COMPLETED
                and task.started_at is not None
                and task.completed_at is not None):
            return (task.completed_at - task.started_at).total_seconds()
        return None

    def get_completion_rate(self, user_id):
        with self._lock:
            self._require_user(user_id)
            tasks = self._tasks_for_user(user_id)
            if not tasks:
                return 0.0
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED
            )
            return completed / len(tasks)

    def get_average_completion_time(self, user_id):
        with self._lock:
            self._require_user(user_id)
            durations = [
                self._completion_seconds(task)
                for task in self._tasks_for_user(user_id)
            ]
            durations = [d for d in durations if d is not None]
            if not durations:
                return None
            return sum(durations) / len(durations)

    def submit_rating(self, rater_id, ratee_id, score, feedback="", task_id=None):
        with self._lock:
            self._require_user(rater_id)
            self._require_user(ratee_id)
            if task_id is not None:
                self._require_task(task_id)
            if rater_id == ratee_id:
                raise ConflictError("a user cannot rate themselves")
            if not isinstance(score, int) or isinstance(score, bool):
                raise ValidationError("score must be an integer 1..5")
            if score < 1 or score > 5:
                raise ValidationError("score must be between 1 and 5")

            rating = Rating(
                id=self._next_id(),
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback if feedback is not None else "",
                task_id=task_id,
                created_at=self._timestamp(),
            )
            self.performance.add(rating)
            return _clone(rating)

    def _ratings_for_user(self, user_id):
        return [
            rating for rating in self.performance.values()
            if rating.ratee_id == user_id
        ]

    def get_ratings_summary(self, user_id):
        with self._lock:
            self._require_user(user_id)
            ratings = self._ratings_for_user(user_id)
            ratings.sort(key=lambda r: r.id)
            count = len(ratings)
            average = (
                sum(r.score for r in ratings) / count if count else 0.0
            )
            return {
                "count": count,
                "average": average,
                "ratings": _clone_list(ratings),
            }

    def get_user_dashboard(self, user_id):
        with self._lock:
            self._require_user(user_id)
            tasks = self._tasks_for_user(user_id)
            total = len(tasks)
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED
            )
            in_progress = sum(
                1 for t in tasks if t.status == TaskStatus.IN_PROGRESS
            )
            not_started = sum(
                1 for t in tasks if t.status == TaskStatus.NOT_STARTED
            )
            completion_rate = (completed / total) if total else 0.0

            durations = [
                self._completion_seconds(t) for t in tasks
            ]
            durations = [d for d in durations if d is not None]
            average_completion_time = (
                sum(durations) / len(durations) if durations else None
            )

            ratings = self._ratings_for_user(user_id)
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count
                if rating_count else 0.0
            )

            return {
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": completion_rate,
                "average_completion_time": average_completion_time,
                "rating_count": rating_count,
                "rating_average": rating_average,
            }

    # ==================================================================
    # Reports
    # ==================================================================
    def project_progress_report(self, project_id):
        with self._lock:
            self._require_project(project_id)
            now = self._timestamp()
            tasks = [
                task for task in self.tasks.values()
                if task.project_id == project_id
            ]

            status_counts = {status.value: 0 for status in TaskStatus}
            overdue = 0
            per_assignee = {}  # type: Dict[int, Dict[str, Any]]

            for task in tasks:
                status_counts[task.status.value] += 1
                if (task.deadline is not None
                        and task.status != TaskStatus.COMPLETED
                        and task.deadline < now):
                    overdue += 1
                if task.assignee_id is not None:
                    bucket = per_assignee.setdefault(
                        task.assignee_id,
                        {"total": 0, "completed": 0},
                    )
                    bucket["total"] += 1
                    if task.status == TaskStatus.COMPLETED:
                        bucket["completed"] += 1

            total = len(tasks)
            completed = status_counts[TaskStatus.COMPLETED.value]
            completion_rate = (completed / total) if total else 0.0

            for bucket in per_assignee.values():
                bucket["completion_rate"] = (
                    bucket["completed"] / bucket["total"]
                    if bucket["total"] else 0.0
                )

            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": completion_rate,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance_report(self, project_id=None):
        with self._lock:
            if project_id is not None:
                self._require_project(project_id)
                scope = [
                    task for task in self.tasks.values()
                    if task.project_id == project_id
                ]
            else:
                scope = list(self.tasks.values())

            assignee_ids = sorted({
                task.assignee_id for task in scope
                if task.assignee_id is not None and task.assignee_id in self.users
            })

            rows = []
            for user_id in assignee_ids:
                user = self.users.get(user_id)
                user_tasks = [
                    task for task in scope if task.assignee_id == user_id
                ]
                rows.append(self._performance_row(user, user_tasks))

            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "project_id": project_id,
                "rows": rows,
            }

    def individual_performance_report(self, user_id):
        with self._lock:
            user = self._require_user(user_id)
            user_tasks = self._tasks_for_user(user_id)
            user_tasks.sort(key=lambda t: t.id)
            row = self._performance_row(user, user_tasks)

            task_rows = [
                {
                    "task_id": task.id,
                    "project_id": task.project_id,
                    "title": task.title,
                    "status": task.status.value,
                }
                for task in user_tasks
            ]

            report = {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
            }
            report.update(row)
            report["tasks"] = task_rows
            return report

    def _performance_row(self, user, tasks):
        total = len(tasks)
        completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
        in_progress = sum(
            1 for t in tasks if t.status == TaskStatus.IN_PROGRESS
        )
        not_started = sum(
            1 for t in tasks if t.status == TaskStatus.NOT_STARTED
        )
        completion_rate = (completed / total) if total else 0.0

        durations = [self._completion_seconds(t) for t in tasks]
        durations = [d for d in durations if d is not None]
        average_completion_time = (
            sum(durations) / len(durations) if durations else None
        )

        ratings = self._ratings_for_user(user.id)
        rating_count = len(ratings)
        rating_average = (
            sum(r.score for r in ratings) / rating_count
            if rating_count else 0.0
        )

        return {
            "user_id": user.id,
            "username": user.username,
            "total_tasks": total,
            "completed_tasks": completed,
            "in_progress_tasks": in_progress,
            "not_started_tasks": not_started,
            "completion_rate": completion_rate,
            "average_completion_time": average_completion_time,
            "rating_count": rating_count,
            "rating_average": rating_average,
        }

    # ------------------------------------------------------------------
    # Report export
    # ------------------------------------------------------------------
    def export_report(self, report, report_format):
        if not isinstance(report, dict):
            raise ValidationError("report must be a dict")
        if not isinstance(report_format, ReportFormat):
            raise ValidationError("report_format must be a ReportFormat")

        if report_format == ReportFormat.CSV:
            return self._export_csv(report)
        if report_format == ReportFormat.PDF:
            return self._export_pdf(report)
        raise ValidationError("unsupported report format")

    def _export_csv(self, report):
        buffer = io.StringIO()
        writer = csv.writer(buffer)

        rows = report.get("rows")
        if isinstance(rows, list):
            if rows:
                columns = list(rows[0].keys())
            else:
                columns = ["user_id"]
            writer.writerow(columns)
            for row in rows:
                writer.writerow([self._csv_cell(row.get(c)) for c in columns])
        else:
            writer.writerow(["metric", "value"])
            for key, value in report.items():
                if isinstance(value, dict):
                    for sub_key, sub_value in value.items():
                        writer.writerow([
                            "{0}.{1}".format(key, sub_key),
                            self._csv_cell(sub_value),
                        ])
                elif isinstance(value, list):
                    writer.writerow([
                        key,
                        "; ".join(self._csv_cell(item) for item in value),
                    ])
                else:
                    writer.writerow([key, self._csv_cell(value)])

        return buffer.getvalue()

    @staticmethod
    def _csv_cell(value):
        if value is None:
            return ""
        if isinstance(value, str):
            return value
        return str(value)

    def _export_pdf(self, report):
        return self._build_pdf(self._report_text_lines(report))

    @staticmethod
    def _report_text_lines(report):
        lines = ["HealthHub Report"]
        report_type = report.get("report_type", "report")
        lines.append("Type: {0}".format(report_type))
        for key, value in report.items():
            if key == "report_type":
                continue
            if isinstance(value, dict):
                lines.append("{0}:".format(key))
                for sub_key, sub_value in value.items():
                    lines.append("  {0}: {1}".format(sub_key, sub_value))
            elif isinstance(value, list):
                lines.append("{0}: {1} item(s)".format(key, len(value)))
                for item in value[:100]:
                    lines.append("  - {0}".format(item))
            else:
                lines.append("{0}: {1}".format(key, value))
        return lines

    @staticmethod
    def _pdf_escape(text):
        text = str(text)
        text = text.replace("\\", "\\\\")
        text = text.replace("(", "\\(").replace(")", "\\)")
        text = text.replace("\r", " ").replace("\n", " ")
        return text

    def _build_pdf(self, text_lines):
        """Assemble a minimal, structurally valid single-page PDF document."""

        content_parts = ["BT", "/F1 12 Tf", "50 760 Td", "14 TL"]
        for index, line in enumerate(text_lines):
            escaped = self._pdf_escape(line)
            if index == 0:
                content_parts.append("({0}) Tj".format(escaped))
            else:
                content_parts.append("T*")
                content_parts.append("({0}) Tj".format(escaped))
        content_parts.append("ET")
        stream = "\n".join(content_parts).encode("latin-1", "replace")

        objects = [
            b"<< /Type /Catalog /Pages 2 0 R >>",
            b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
            (
                b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
                b"/Resources << /Font << /F1 5 0 R >> >> /Contents 4 0 R >>"
            ),
            (
                b"<< /Length " + str(len(stream)).encode("ascii")
                + b" >>\nstream\n" + stream + b"\nendstream"
            ),
            b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
        ]

        out = bytearray()
        out += b"%PDF-1.4\n"
        offsets = []
        for number, body in enumerate(objects, start=1):
            offsets.append(len(out))
            out += str(number).encode("ascii") + b" 0 obj\n"
            out += body + b"\nendobj\n"

        xref_position = len(out)
        size = len(objects) + 1
        out += b"xref\n"
        out += b"0 " + str(size).encode("ascii") + b"\n"
        out += b"0000000000 65535 f \n"
        for offset in offsets:
            out += ("%010d 00000 n \n" % offset).encode("ascii")
        out += b"trailer\n"
        out += b"<< /Size " + str(size).encode("ascii") + b" /Root 1 0 R >>\n"
        out += b"startxref\n"
        out += str(xref_position).encode("ascii") + b"\n"
        out += b"%%EOF"
        return bytes(out)


